1	interface QuoteItem {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface QuoteStep {
8	  op: "quote";
9	  items: QuoteItem[];
10	}
11	
12	interface Scenario {
13	  customer: { yearsWithMHPCO: number };
14	  steps: QuoteStep[];
15	}
16	
17	const BASE_PREMIUM: Record<string, number> = {
18	  amulet: 60,
19	  sword: 100,
20	};
21	
22	const FIRST_INSURANCE_RATE = 0.1;
23	const PROCESSING_FEE = 5;
24	
25	const CURSE_SURCHARGE_RATE = 0.5;
26	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
27	const HIGH_ENCHANTMENT_THRESHOLD = 5;
28	
29	function itemBasePremium(item: QuoteItem): number {
30	  return BASE_PREMIUM[item.type] ?? 0;
31	}
32	
33	function itemSurcharges(item: QuoteItem): number {
34	  const base = itemBasePremium(item);
35	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
36	  const highEnchantmentSurcharge =
37	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
38	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
39	      : 0;
40	  return curseSurcharge + highEnchantmentSurcharge;
41	}
42	
43	function priceQuoteStep(step: QuoteStep): { premium: number } {
44	  const policyBase = step.items.reduce(
45	    (sum, item) => sum + itemBasePremium(item),
46	    0,
47	  );
48	  const itemSurchargeTotal = step.items.reduce(
49	    (sum, item) => sum + itemSurcharges(item),
50	    0,
51	  );
52	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
53	  const premium = Math.ceil(
54	    policyBase + itemSurchargeTotal + firstInsurance + PROCESSING_FEE,
55	  );
56	  return { premium };
57	}
58	
59	export function runScenario(scenario: Scenario): {
60	  results: { premium: number }[];
61	} {
62	  const results = scenario.steps.map(priceQuoteStep);
63	  return { results };
64	}
